from scipy.optimize._numdiff import approx_derivative
import numpy as np


def fun(x):
    assert x.ndim == 1  # if x is scalar or 0d, ndim will be 0
    return np.sum(x**2)


array_scalar = np.float64(1)
array_0d = np.ones([])
array_1d = np.ones([1])

expected = np.array([2])

for x0 in [array_scalar, array_0d, array_1d]:
    for method in ['3-point', '2-point', 'cs']:
        for rel_step in [None, 1e-8]:
            for abs_step in [None, 1e-8]:
